        // 开始压缩
        int temp = 0;
        if (file.isDirectory()) &#123; // 判断是否是文件夹
            File lists[] = file.listFiles(); // 列出全部子文件
            for (int i = 0; i &lt; lists.length; i++) &#123;
                input = new FileInputStream(lists[i]); // 定义文件的输入流
                zipOut.putNextEntry(new ZipEntry(file.getName()
