                System.out.println("正在压缩" + lists[i].getName());
                while ((temp = input.read()) != -1) &#123; // 读取内容
                    zipOut.write(temp); // 压缩输出
                &#125;
                input.close(); // 关闭输入流
            &#125;
        &#125;
        zipOut.close(); // 关闭输出流
