 繁忙的都市：最小生成树
城市 C 是一个非常繁忙的大都市，城市中的道路十分的拥挤，于是市长决定对其中的道路进行改造。城市 C 的道路是这样分布的：城市中有 n 个交叉路口，有些交叉路口之间有道路相连，两个交叉路口之间最多有一条道路相连接。这些道路是双向的，且把所有的交叉路口直接或间接的连接起来了。每条道路都有一个分值，分值越小表示这个道路越繁忙，越需要进行改造。但是市政府的资金有限，市长希望进行改造的道路越少越好，于是他提出下面的要求：
改造的那些道路能够把所有的交叉路口直接或间接的连通起来。
在满足要求 (1) 的情况下，改造的道路尽量少。
在满足要求 (1)、(2) 的情况下，改造的那些道路中分值最大的道路分值尽量小。
任务：作为市规划局的你，应当作出最佳的决策，选择那些道路应当被修建。
输入格式:
第一行有两个整数 n,m 表示城市有 n 个交叉路口，m 条道路。
接下来 m 行是对每条道路的描述，u,v,c 表示交叉路口 u 和 v 之间有道路相连，分值为 c 。  1≤n≤300,1≤c≤10000
输出格式:
两个整数 s,max，表示你选出了几条道路，分值最大的那条道路的分值是多少。
输入样例:
4 5
1 2 3
1 4 5
2 4 7
2 3 6
3 4 8
输出样例:
3 6
代码:
#include &lt;algorithm&gt;
#include &lt;iostream&gt;
using namespace std;
class Node &#x2F;&#x2F;路径类
&#123;
public:
    int a, b, c; &#x2F;&#x2F;节点1，节点2，权
&#125; list[10000];
int sign[10000];&#x2F;&#x2F;用于归类，下标是路径，数值是路径对应的类的编号
int find(int);&#x2F;&#x2F;用于找到路径属于哪一类
bool compare(Node, Node);
main()
&#123;
    int n, m, maxx&#x3D;0, num&#x3D;0;
    cin &gt;&gt; n &gt;&gt; m;
    for (int i &#x3D; 1; i &lt;&#x3D; n; i++)&#x2F;&#x2F;初始化sign数组，每个路基都属于不同类
        sign[i] &#x3D; i;
    for (int i &#x3D; 1; i &lt;&#x3D; m; i++)&#x2F;&#x2F;建图
        cin &gt;&gt; list[i].a &gt;&gt; list[i].b &gt;&gt; list[i].c;
    sort(list + 1, list + 1 + m, compare); &#x2F;&#x2F;对路径按权进行排序
    for (int i &#x3D; 1; i &lt;&#x3D; m; i++)           &#x2F;&#x2F;遍历所有路径
    &#123;
        int u &#x3D; list[i].a, v &#x3D; list[i].b;
        if (find(u) &#x3D;&#x3D; find(v)) &#x2F;&#x2F;左节点和右节点属于一类，则已经被连接，说明此路径不是两个节点的最短路径
            continue;
        num++;
        sign[find(u)] &#x3D; find(v); &#x2F;&#x2F;连接左节点和右节点，即两个节点归属一类
        maxx &#x3D; max(maxx, list[i].c); &#x2F;&#x2F;更新最大分值
    &#125;
    cout &lt;&lt; num &lt;&lt; &#39; &#39; &lt;&lt; maxx;
&#125;
bool compare(Node a, Node b)
&#123;
    return a.c &lt; b.c;
&#125;
int find(int x)&#x2F;&#x2F;难点
&#123;
    if (sign[x] !&#x3D; x)&#x2F;&#x2F;如果不是初始化时的值
        sign[x] &#x3D; find(sign[x]);&#x2F;&#x2F;则更新自己的值
    return sign[x];
&#125;
 排列论文:拓扑排序
给定编号为1至n的n篇论文，以及m个形如d, u (1≤d,u≤n,d

=u)的引用关系，表示论文论文d中定义的一个名词在论文u中被引用。现在要对这n篇论文重新排列，排列方案须满足如下要求：一篇论文引用的名词必须在排在他前面的论文中被定义过。
请编写程序粗略计算都有多少种满足要求的方案，如果无满足要求的方案则输出0，如果有唯一方案则输出1，如果有多种方案则输出2。
输入格式:
输入包含多组数据，每组数据第一行为两个正整数n和m，分别表示论文篇数和引用关系数，均不超过100。接下来m行表示论文引用关系，每行为空格间隔的2个正整数d和u，表示论文论文d中定义的一个名词在论文u中被引用。
输出格式:
对于每组数据输出一个整数：无满足要求的排列方案则输出0，如果有唯一方案则输出1，如果有多种方案则输出2。
输入样例:
5 4
1 5
5 2
3 2
4 3
5 4
3 1
4 2
1 5
5 4
输出样例:
2
1
代码:
#include &lt;cstring&gt;
#include &lt;deque&gt;
#include &lt;iostream&gt;
using namespace std;
int howMuchBefore[1000];
deque&lt;int&gt; dict[1000];&#x2F;&#x2F;节点名称对子节点的索引
deque&lt;int&gt; outcome; &#x2F;&#x2F;保存结果
deque&lt;int&gt; list;   &#x2F;&#x2F;队列
main()
&#123;
    int n, m;
    while (cin &gt;&gt; n &gt;&gt; m)
    &#123;
        bool sign &#x3D; 0; &#x2F;&#x2F;是否有多种结果
        int num &#x3D; 0;  &#x2F;&#x2F; 起点的数量
        for (int i &#x3D; 1; i &lt;&#x3D; m; i++)
        &#123;
            int d, u;
            cin &gt;&gt; d &gt;&gt; u;
            dict[d].push_back(u); &#x2F;&#x2F;给节点d添加一个子节点u
            howMuchBefore[u]++;     &#x2F;&#x2F;在u前面的论文个数增加
        &#125;
        for (int i &#x3D; 1; i &lt;&#x3D; n; i++)
        &#123;
            if (howMuchBefore[i] &#x3D;&#x3D; 0)&#x2F;&#x2F;拓扑排序，先找出所有起点
            &#123;              
                list.push_back(i); &#x2F;&#x2F;找到就加入队列
                num++;
            &#125;
        &#125;
        if (num &gt; 1) &#x2F;&#x2F;起点太多，排序肯定不唯一
            sign &#x3D; 1;
        while (!list.empty())
        &#123;
            int p &#x3D; list.front();&#x2F;&#x2F;取队列中最前面的元素为p
            list.pop_front();&#x2F;&#x2F;删去队列中最前的元素
            outcome.push_back(p);&#x2F;&#x2F;添加到排序队列中去
            for (int i &#x3D; 0; i &lt; dict[p].size(); i++)&#x2F;&#x2F;遍历p的子节点
            &#123;
                int y &#x3D; dict[p][i];
                howMuchBefore[y]--;&#x2F;&#x2F;告诉这些子节点，在你们之前的元素减少一个
                if (!howMuchBefore[y])&#x2F;&#x2F;如果y的前面没有元素了，只能直接将y放入队列
                &#123;
                    list.push_back(y);
                &#125;
            &#125;
        &#125;
        if (outcome.size() &#x3D;&#x3D; n) &#x2F;&#x2F;可以进行拓扑排序
        &#123;
            if (!sign)
                cout &lt;&lt; &quot;1&quot; &lt;&lt; endl;
            else
                cout &lt;&lt; &quot;2&quot; &lt;&lt; endl;
        &#125;
        else
            cout &lt;&lt; &quot;0&quot; &lt;&lt; endl;    &#x2F;&#x2F;不能拓扑排序
        for (int i &#x3D; 0; i &lt; m; i++) &#x2F;&#x2F;清空操作
            dict[i].clear();
        outcome.clear();
        while (!list.empty())
            list.pop_front();
        memset(howMuchBefore, 0, sizeof(howMuchBefore));
    &#125;
