代码:
#include &lt;iostream&gt;
#include &lt;cstring&gt;
using namespace std;
int map[200][200];&#x2F;&#x2F;邻接矩阵，出发点到目标的距离&#x3D;map[出发点][目标];距离为0视为无限大
main()
&#123;
    int v, e;
    while (cin &gt;&gt; v &gt;&gt; e)
    &#123;
        memset(map, 0, sizeof(map));&#x2F;&#x2F;初始化为无限大
        for (int t &#x3D; 0; t &lt; e; t++)&#x2F;&#x2F;建图
        &#123;
            int i, j;
            cin &gt;&gt; i &gt;&gt; j &gt;&gt; map[i][j];
            map[j][i] &#x3D; map[i][j];
        &#125;
        for (int k &#x3D; 0; k &lt; v; k++)		&#x2F;&#x2F;Floyd算法找最短路
            for (int j &#x3D; 0; j &lt; v; j++)	
                for (int i &#x3D; 0; i &lt; v; i++)
                    if ((map[i][j] &gt; map[i][k] + map[k][j] || map[i][j] &#x3D;&#x3D; 0) &amp;&amp; map[i][k] !&#x3D; 0 &amp;&amp; map[k][j] !&#x3D; 0)
                        map[i][j] &#x3D; map[i][k] + map[k][j];
        int sum &#x3D; 0;
        int minsum &#x3D; 99999;
        int minn &#x3D; 0;
        for (int i &#x3D; 0; i &lt; v; i++)&#x2F;&#x2F;遍历所有起点找到最短的距离之和
        &#123;
            for (int j &#x3D; 0; j &lt; v; j++)
            &#123;
                sum +&#x3D; map[i][j];
            &#125;
            if (minsum &gt; sum)
            &#123;
                minsum &#x3D; sum;
                minn &#x3D; i;
            &#125;
            sum &#x3D; 0;
        &#125;
        cout &lt;&lt; minn&lt;&lt;endl;
    &#125;
