代码:
#include &lt;iostream&gt;
#include &lt;map&gt;
#include &lt;deque&gt;
using namespace std;
class Node
&#123;
public:
    int value;
    int front;
    int length &#x3D; 99999;
    map&lt;int, int&gt; connect; &#x2F;&#x2F; first:子节点下标，second:到该子节点的路径权重
&#125; list[20];&#x2F;&#x2F;采用邻接表
bool sign[20];
int v, e;
void dij(int);
void findpath(int, int);
main()
&#123;
    cin &gt;&gt; v &gt;&gt; e;
    for (int i &#x3D; 0; i &lt; e &#x2F; 2; i++)&#x2F;&#x2F;建无向图
    &#123;
        int a, b, c;
        cin &gt;&gt; a &gt;&gt; b &gt;&gt; c;
        list[a].value &#x3D; a;
        list[b].value &#x3D; b;
        list[a].connect[b] &#x3D; c;
        list[b].connect[a] &#x3D; c;
    &#125;
    int n, m;
    cin &gt;&gt; n &gt;&gt; m;
    if (n &#x3D;&#x3D; m)
        cout &lt;&lt; n &lt;&lt; &quot;--&gt;&quot; &lt;&lt; m &lt;&lt; &#39;:&#39; &lt;&lt; 0;
    else
    &#123;
        dij(n);&#x2F;&#x2F;从n开始进行迪杰斯塔拉
        findpath(n, m);
        cout &lt;&lt; m &lt;&lt; &#39;:&#39; &lt;&lt; list[m].length;
    &#125;
&#125;
void dij(int s)
&#123;
    int minn &#x3D; 0;&#x2F;&#x2F;保存目前找到的 离s最近 的节点
    int num &#x3D; 0;&#x2F;&#x2F;保存最小的路径长度
    list[s].length &#x3D; 0;&#x2F;&#x2F;对起点长度先标记为0
    sign[s] &#x3D; 1;&#x2F;&#x2F;不进行比较的标记
    deque&lt;int&gt; que;&#x2F;&#x2F;类似于广搜的队列
    que.push_back(s);
    while (que.size() !&#x3D; 0)&#x2F;&#x2F;类广度优先搜索
    &#123;
        int min &#x3D; 99999;
        for (auto i &#x3D; list[*que.begin()].connect.begin(); i !&#x3D; list[*que.begin()].connect.end(); i++)&#x2F;&#x2F;对当前 离s最近 的节点进行子节点遍历
        &#123;
            if (sign[list[i-&gt;first].value])&#x2F;&#x2F;如果已经被标记为不进行比较
                continue;
            if (list[i-&gt;first].length &gt; list[*que.begin()].length + i-&gt;second)&#x2F;&#x2F;还可以更小
            &#123;
                list[i-&gt;first].length &#x3D; list[*que.begin()].length + i-&gt;second; &#x2F;&#x2F;计算路程
                list[i-&gt;first].front &#x3D; list[*que.begin()].value;			   &#x2F;&#x2F;记录下标
            &#125;
        &#125;
        for (int i &#x3D; 0; i &lt; v; i++)&#x2F;&#x2F;找到 离s最近 的节点
            if (list[i].length &lt; min &amp;&amp; sign[i] !&#x3D; 1)
            &#123;
                min &#x3D; list[i].length;
                minn &#x3D; i;
            &#125;
        sign[minn] &#x3D; 1;&#x2F;&#x2F;标记
        num++;
        que.pop_back();&#x2F;&#x2F;删除队首元素
        if (num &lt; v)&#x2F;&#x2F;还没搜完
            que.push_back(minn);&#x2F;&#x2F;加入此节点
    &#125;
&#125;
void findpath(int start, int target)&#x2F;&#x2F;递归找路
&#123;
    if (target &#x3D;&#x3D; start)
        return;
    findpath(start, list[target].front);
    cout &lt;&lt; list[target].front &lt;&lt; &quot;--&gt;&quot;;
