 生化危机:深度优先搜索
人类正在经历一场生化危机，许多城市已经被病毒侵袭，这些城市中的人们为了避免感染病毒，计划开车逃往其他没有被病毒入侵的城市（安全城市）。有些城市之间有公路直达，有些没有。虽然他们知道哪些城市是安全的，但是不知道有没有一条安全路径能够到达安全城市（只有该路径上经过的所有城市都是安全的，该路径才是安全路径）。请你编写一个程序帮助他们判断。
输入格式:
输入第一行为三个正整数，分别表示所有城市个数m（m&lt;=100）、安全城市个数n（m&lt;=50）、公路个数k（k&lt;=100）。随后一行给出n个安全城市的编号。随后k行，每一行给出两个整数，表示连接一条公路的两个城市编号。最后一行输入两个整数，分别表示当前所在城市s、目标城市d。每行整数之间都用空格分隔。
输出格式:
若目标城市已被病毒入侵（非安全城市），输出&quot;The city i is not safe!&quot;；若目标城市为安全城市且从当前所在城市能够经过一条安全路径到达目标城市，输出&quot;The city can arrive safely！&quot;；若目标城市为安全城市但是从当前所在城市没有一条安全路径到达目标城市，输出&quot;The city can not arrive safely！&quot;，i为目标城市编号。
输入样例1:
5 2 5
3 4
0 1
0 2
0 4
1 2
2 4
0 4
输出样例1:
The city 4 can arrive safely!
输入样例2:
5 2 5
3 4
0 1
0 2
0 4
1 2
2 4
0 3
输出样例2:
The city 3 can not arrive safely!
输入样例3:
5 2 5
3 4
0 1
0 2
0 4
1 2
2 4
0 1
输出样例3:
The city 1 is not safe!
代码
#include &lt;iostream&gt;
using namespace std;
struct city&#x2F;&#x2F;城市类
&#123;
    bool done &#x3D; 0;&#x2F;&#x2F;是否被搜索过
    bool safe &#x3D; 0;&#x2F;&#x2F;是否安全
    int conect[101] &#x3D; &#123;0&#125;;&#x2F;&#x2F;连接的城市
    int conectnum &#x3D; 0;&#x2F;&#x2F;连接城市的数量
&#125;;
bool dfs(city a[], int start, int end);
main()
&#123;
    int m, n, k;
    cin &gt;&gt; m &gt;&gt; n &gt;&gt; k;
    city a[m];
    for (int i &#x3D; 0; i &lt; n; i++)&#x2F;&#x2F;建图
    &#123;
        int no;
        cin &gt;&gt; no;
        a[no].safe &#x3D; 1;
    &#125;
    for (int i &#x3D; 0; i &lt; k; i++)
    &#123;
        int d, b;
        cin &gt;&gt; d &gt;&gt; b;
        a[d].conect[a[d].conectnum] &#x3D; b;
        a[d].conectnum++;
        a[b].conect[a[b].conectnum] &#x3D; d;
        a[b].conectnum++;
    &#125;
    int there, that;
    cin &gt;&gt; there &gt;&gt; that;
    if (!(a[that].safe))
    &#123;
        cout &lt;&lt; &quot;The city &quot; &lt;&lt; that &lt;&lt; &quot; is not safe!&quot;;
        return 0;
    &#125;
    if (dfs(a, there, that))
        cout &lt;&lt; &quot;The city &quot; &lt;&lt; that &lt;&lt; &quot; can arrive safely!&quot;;
    else
        cout &lt;&lt; &quot;The city &quot; &lt;&lt; that &lt;&lt; &quot; can not arrive safely!&quot;;
&#125;
bool dfs(city a[], int start, int end)&#x2F;&#x2F;传入保存城市的数组，开始节点，结束节点
&#123;
    if (start &#x3D;&#x3D; end)&#x2F;&#x2F;找到
        return true;
    if (a[start].done)&#x2F;&#x2F;被搜索过
        return false;
    a[start].done &#x3D; 1;&#x2F;&#x2F;标记为被搜索过
    for (int i &#x3D; 0; i &lt; a[start].conectnum; i++)&#x2F;&#x2F;对相连的城市进行深度优先搜索
        if (dfs(a, a[start].conect[i], end))
            return true;
    return false;
