    &#123;
        cin &gt;&gt; list[i];
    &#125;
    w.insert(list[0]);
    for (int i &#x3D; 1; i &lt; n;i++)
    &#123;
        int cache[200],p&#x3D;0;
        for (auto it &#x3D; w.begin(); it !&#x3D; w.end();it++)
        &#123;
                cache[p++] &#x3D; abs(*it + list[i]);
