 异或数列
Alice 和 Bob 正在玩一个异或数列的游戏。初始时，Alice 和 Bob 分别有一个整数 a 和 b，有一个给定的长度为 n 的公共数列 X1, X2, · · · , Xn。
Alice 和 Bob 轮流操作，Alice 先手，每步可以在以下两种选项中选一种：
选项 1：从数列中选一个 Xi 给 Alice 的数异或上，或者说令 a 变为 a ⊕ Xi。（其中 ⊕ 表示按位异或）
选项 2：从数列中选一个 Xi 给 Bob 的数异或上，或者说令 b 变为 b ⊕ Xi。
每个数 Xi 都只能用一次，当所有 Xi 均被使用后（n 轮后）游戏结束。游戏结束时，拥有的数比较大的一方获胜，如果双方数值相同，即为平手。
现在双方都足够聪明，都采用最优策略，请问谁能获胜？
要不直接模拟。。。。
#include &lt;iostream&gt;
#include &lt;cstring&gt;
using namespace std;
const int N &#x3D; 2e5 + 5;
long long w[N];
int n;
int cnt[25];

void op(long long x)
&#123;
    int t &#x3D; 0;
    while (x)
    &#123;
        t++;
        if (x &amp; 1)
            cnt[t]++;
        x &gt;&gt;&#x3D; 1;
    &#125;
&#125;
void solve()
&#123;
    memset(cnt, 0, sizeof cnt);
    int sum &#x3D; 0;
    for (int i &#x3D; 1; i &lt;&#x3D; n; i++)
        op(w[i]), sum ^&#x3D; w[i];
    if (!sum)
    &#123;
        cout &lt;&lt; 0 &lt;&lt; endl;
        return;
    &#125;
    for (int i &#x3D; 20; i &gt; 0; i--)
    &#123;
        if (cnt[i] &#x3D;&#x3D; 1)
        &#123;
            cout &lt;&lt; 1 &lt;&lt; endl;
            return;
        &#125;
        if (cnt[i] &amp; 1)
        &#123;
            if (n &amp; 1)
            &#123;
                cout &lt;&lt; 1 &lt;&lt; endl;
                return;
            &#125;
            else
            &#123;
                cout &lt;&lt; -1 &lt;&lt; endl;
                break;
            &#125;
        &#125;
    &#125;
&#125;
int main()
&#123;
    int t;
    cin &gt;&gt; t;
    while (t--)
    &#123;
        cin &gt;&gt; n;
        for (int i &#x3D; 1; i &lt;&#x3D; n; i++)
        &#123;
            cin &gt;&gt; w[i];
        &#125;
        solve();
    &#125;
&#125;
